import { CAvatar, CCol, CFormLabel, CNav, CNavItem, CRow, CTabContent, CTabPane, CNavLink } from '@coreui/react';
import React, { useEffect, useState } from 'react'
import { getBillingDeatilsData, getTransactionHistory, getUserProfileInformation, getUserTaxInfromation } from 'src/components/services/UserDetailsApi';
import GoBackComponent from 'src/utils/GoBackComponent'
import DataTable from "react-data-table-component";
import { tableTransactionHistoryConstant } from './tableTransactionHistoryConstant';
import { useLocation, useParams } from 'react-router-dom';
import { download_file, tabInfo } from 'src/utils/Common';
import { customStyles } from "../../utils/tableCustomStyles";


const UserDetails = () => {
    const location = useLocation();
    const { state } = location;
    let { id } = useParams();
    const [userId] = useState(id)
    const [userPersonalInformation, setUserPersonalInformation] = useState({});
    const [userTaxInformation, setUserTaxInformation] = useState({});
    const [transactionHistory, setTransactionHistory] = useState([])
    const [billingDetails, setBillingDetails] = useState([]);
    const [loading, setLoading] = useState(false)
    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [activeKey, setActiveKey] = useState(state?.activeTab ? state.activeTab : "PERSONAL_INFORMATION")

    useEffect(() => {
        if(activeKey === "PERSONAL_INFORMATION"){
            getUserPersonalInfromationDetails();
        }else if (activeKey === "SUBSCRIPTION_HISTORY"){
            getSubscriptionHistoryByUserId(0, perPage);
        }else if (activeKey === "TAX_INFORMATION"){
            getUserTaxInfromationDetails();
        }else{
            getUserBillingDetailsById(0, perPage);
        }
    }, [activeKey])

    const getUserPersonalInfromationDetails = async () => {
        let response = await getUserProfileInformation(userId)
        if (response?.status === "200 OK") {
            setUserPersonalInformation(response?.body)
        }
    }

    const getUserTaxInfromationDetails = async () => {
        let response = await getUserTaxInfromation(userId)
        if (response?.status === "200 OK") {
            setUserTaxInformation(response?.body)
        }
    }

    const getSubscriptionHistoryByUserId = async (page, size) => {
        let data = {
            page: page,
            size: size,
            userId: userId
        }
        setLoading(true)
        let response = await getTransactionHistory(data)
        if (response?.status === "200 OK") {
            setTransactionHistory(response?.body?.content)
            setTotalRows(response?.body?.totalElements)
            setLoading(false)
        }
    }

    const getUserBillingDetailsById = async(page,size) => {
        let data = {
          page: page,
          size: size,
          userId: userId 
        }
        setLoading(true)
        let response = await getBillingDeatilsData(data)
        if (response?.status === "200 OK") {
          setBillingDetails(response?.body?.content)
          setTotalRows(response?.body?.totalElements)
          setLoading(false)
        }
    }

    const handleChangeTab = (key) => {
        setActiveKey(key);
        setLoading(false);
        setTotalRows(0);
        setPerPage(10);
    }

    const handlePageChange = (page) => {
        if(activeKey === "SUBSCRIPTION_HISTORY"){
            getSubscriptionHistoryByUserId(page - 1, perPage);
        }else{
            getUserBillingDetailsById(page - 1, perPage);
        }
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        setPerPage(newPerPage);
        if(activeKey === "SUBSCRIPTION_HISTORY"){
            getSubscriptionHistoryByUserId(page - 1, newPerPage);
        }else{
            getUserBillingDetailsById(page - 1, newPerPage);
        }
    };


    return (
        <>
            <GoBackComponent goBackData={"members-summary"} />
            <CNav variant="tabs" role="tablist">
                {tabInfo && tabInfo.map(({ value, label }) => (
                    <CNavItem key={value} role="presentation">
                        <CNavLink active={activeKey === value} component="button" role="tab" aria-controls={`${value}-tab-pane`} aria-selected={activeKey === value} style={{ color: activeKey === value ? '#03a680' : '#000' }} onClick={() => handleChangeTab(value)} >{label}</CNavLink>
                    </CNavItem>))}
            </CNav>
            <CTabContent>
                {activeKey === "PERSONAL_INFORMATION" &&
                    <CTabPane role="tabpanel" aria-labelledby="home-tab-pane" visible={activeKey === "PERSONAL_INFORMATION"} style={{ paddingTop: "20px" }}>
                       <CRow>
                       <CAvatar src={userPersonalInformation?.attachment?.attachmentUrl ? userPersonalInformation.attachment.attachmentUrl : "https://cdn.dscovr.com/images/users1.webp"} color="secondary" style={{ width: '110px', height: '110px', alignItems: "normal" }} />
                       <CCol md={3}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Code:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.code}</div>
                            </div>
                        </CCol>
                       </CRow>
                       <br/>
                        <CRow >
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">First Name:</CFormLabel>
                                    <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.firstName}</div>
                                </div>
                            </CCol>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Last Name:</CFormLabel>
                                    <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.lastName}</div>
                                </div>
                            </CCol>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Email:</CFormLabel>
                                    <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.email}</div>
                                </div>
                            </CCol>
                        </CRow>
                        <CRow>

                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Phone number:</CFormLabel>
                                    <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.phone}</div>
                                </div>
                            </CCol>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Company Name:</CFormLabel>
                                    <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.company}</div>
                                </div>
                            </CCol>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Address line 1:</CFormLabel>
                                    <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.addressDetail?.addressLine1}</div>
                                </div>
                            </CCol>
                        </CRow>
                        <CRow>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Address line 2:</CFormLabel>
                                    <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.addressDetail?.addressLine2}</div>
                                </div>
                            </CCol>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Country:</CFormLabel>
                                    <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.addressDetail?.country}</div>
                                </div>
                            </CCol>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">State:</CFormLabel>
                                    <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.addressDetail?.state}</div>
                                </div>
                            </CCol>

                        </CRow>

                        <CRow>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">City:</CFormLabel>
                                    <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.addressDetail?.city}</div>
                                </div>
                            </CCol>
                            <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">Pincode:</CFormLabel>
                                    <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.addressDetail?.pincode}</div>
                                </div>
                            </CCol>
                            {/* <CCol md={4}>
                                <div className='form-group'>
                                    <CFormLabel htmlFor="exampleFormControlTextarea1">State:</CFormLabel>
                                    <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userPersonalInformation?.addressDetail?.state}</div>
                                </div>
                            </CCol> */}

                        </CRow>


                    </CTabPane>}
                {activeKey === "SUBSCRIPTION_HISTORY" &&
                    <CTabPane role="tabpanel" aria-labelledby="profile-tab-pane" visible={activeKey === "SUBSCRIPTION_HISTORY"} style={{ paddingTop: "20px" }}>
                        <DataTable
                            columns={tableTransactionHistoryConstant("SUBSCRIPTION_HISTORY")}
                            data={transactionHistory}
                            customStyles={customStyles}
                            pagination
                            paginationPerPage={perPage}
                            pointerOnHover
                            progressPending={loading}
                            paginationServer
                            paginationTotalRows={totalRows}
                            onChangeRowsPerPage={handlePerRowsChange}
                            onChangePage={handlePageChange}
                            fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                        />
                    </CTabPane>}

                {activeKey === "TAX_INFORMATION" &&
                    <CTabPane role="tabpanel" aria-labelledby="contact-tab-pane" visible={activeKey === "TAX_INFORMATION"} style={{ paddingTop: "20px" }}>
                    <CRow>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Address line 1:</CFormLabel>
                                <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.addressLine1}</div>
                            </div>
                        </CCol>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Address line 2:</CFormLabel>
                                <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.addressLine2}</div>
                            </div>
                        </CCol>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Country:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.country}</div>
                            </div>
                        </CCol>

                    </CRow>

                    <CRow>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">State:</CFormLabel>
                                <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.state}</div>
                            </div>
                        </CCol>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">City:</CFormLabel>
                                <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.city}</div>
                            </div>
                        </CCol>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Pin code:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.pincode}</div>
                            </div>
                        </CCol>
                    </CRow>

                    <CRow>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">Pan number:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.panNumber}</div>
                            </div>
                        </CCol>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">GST number:</CFormLabel>
                                <div className='form-control' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.gstNumber}</div>
                            </div>
                        </CCol>
                        <CCol md={4}>
                            <div className='form-group'>
                                <CFormLabel htmlFor="exampleFormControlTextarea1">DUNS number:</CFormLabel>
                                <div className='form-control text-truncate' style={{ height: 'auto', minHeight: '40px' }}>{userTaxInformation?.dunsNumber}</div>
                            </div>
                        </CCol>
                    </CRow>
                    <CRow>
                        {userTaxInformation?.attachment &&
                            <CCol>
                                <div className='d-flex flex-wrap'>
                                    <div className="previewPan">
                                        <span>
                                            <a href={"javascript:void(0)"} onClick={(e) => download_file(e, userTaxInformation?.attachment?.attachmentUrl)} rel="noopener noreferrer">
                                                <img src={userTaxInformation?.attachment?.attachmentType == "PDF" ? "https://cdn.wseinfratech.com/pdf_icon.svg" : userTaxInformation?.attachment?.attachmentType == "DOCUMENT" ? "https://cdn.wseinfratech.com/word_icon.svg" : "https://cdn.wseinfratech.com/excel_icon.svg"} alt="attachment-image" />
                                            </a>
                                        </span>
                                    </div>
                                </div>
                            </CCol>
                        }
                    </CRow>

                    </CTabPane>}

                {activeKey === "BILLING_DETAILS" &&
                    <CTabPane role="tabpanel" aria-labelledby="disabled-tab-pane" visible={activeKey === "BILLING_DETAILS"} style={{ paddingTop: "20px" }}>
                        <DataTable
                            columns={tableTransactionHistoryConstant("BILLING_DETAILS")}
                            data={billingDetails}
                            customStyles={customStyles}
                            pagination
                            paginationPerPage={perPage}
                            pointerOnHover
                            progressPending={loading}
                            paginationServer
                            paginationTotalRows={totalRows}
                            onChangeRowsPerPage={handlePerRowsChange}
                            onChangePage={handlePageChange}
                            fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                        />
                    </CTabPane>}
            </CTabContent>
        </>
    )
}

export default UserDetails;
